files.content:
.mrg-copy-button {
  align-items: center;
  appearance: none;
  background: var(--mrg-semantic-color-background-canvas);
  border: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-interactive);
  border-radius: var(--mrg-semantic-radius-control);
  box-sizing: border-box;
  color: var(--mrg-semantic-color-foreground-primary);
  cursor: pointer;
  display: inline-flex;
  font: inherit;
  font-weight: var(--mrg-semantic-font-weight-label);
  gap: var(--mrg-semantic-density-control-gap);
  justify-content: center;
  max-inline-size: 100%;
  min-block-size: var(--mrg-semantic-size-target-preferred);
  min-inline-size: var(--mrg-semantic-size-target-preferred);
  overflow-wrap: anywhere;
  padding-block: var(--mrg-semantic-space-inline-sm);
  padding-inline: var(--mrg-semantic-space-inline-lg);
  transition: background-color var(--mrg-semantic-motion-duration-transition)
    var(--mrg-semantic-motion-easing-standard);
}

.mrg-copy-button [data-slot="copy-button-icon"] {
  flex: none;
}

.mrg-copy-button [data-slot="copy-button-status"] {
  min-inline-size: 0;
  overflow-wrap: anywhere;
}

.mrg-copy-button:not(:disabled):not([data-status="copying"]):hover {
  background: var(--mrg-semantic-color-background-surface);
}

.mrg-copy-button:not(:disabled):not([data-status="copying"]):active {
  background: var(--mrg-semantic-color-background-surface-sunken);
}

.mrg-copy-button:focus-visible {
  outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
  outline-offset: var(--mrg-semantic-focus-offset);
}

.mrg-copy-button:disabled {
  border-color: var(--mrg-semantic-color-border-disabled);
  color: var(--mrg-semantic-color-foreground-disabled);
  cursor: not-allowed;
}

.mrg-copy-button[data-status="copying"] {
  cursor: progress;
}

.mrg-copy-button[data-status="copied"] [data-slot="copy-button-icon"] {
  color: var(--mrg-semantic-color-status-success-foreground);
}

.mrg-copy-button[data-status="error"] [data-slot="copy-button-icon"] {
  color: var(--mrg-semantic-color-status-danger-foreground);
  font-weight: var(--mrg-semantic-font-weight-strong);
}

@media (prefers-reduced-motion: reduce) {
  .mrg-copy-button {
    transition: none;
  }
}

@media (forced-colors: active) {
  .mrg-copy-button {
    background: ButtonFace;
    border-color: ButtonBorder;
    color: ButtonText;
  }

  .mrg-copy-button[data-status="copied"] [data-slot="copy-button-icon"],
  .mrg-copy-button[data-status="error"] [data-slot="copy-button-icon"] {
    color: Highlight;
  }

  .mrg-copy-button:disabled {
    border-color: GrayText;
    color: GrayText;
  }
}

"use client";

import { forwardRef, useState, type ButtonHTMLAttributes, type MouseEventHandler } from "react";

import { runButtonActivation } from "../button/button-state";
import { useMergoraMessage } from "../provider/index";
import "./copy-button.css";

export type CopyButtonStatus = "idle" | "copying" | "copied" | "error";

export interface ClipboardEnvironment {
  readonly clipboard?: { writeText(text: string): Promise<void> };
  readonly document?: Document;
}

export async function writeClipboardText(
  text: string,
  environment: ClipboardEnvironment = {
    ...(typeof navigator === "undefined" || navigator.clipboard === undefined
      ? {}
      : { clipboard: navigator.clipboard }),
    ...(typeof document === "undefined" ? {} : { document }),
  },
): Promise<"clipboard" | "fallback"> {
  if (environment.clipboard !== undefined) {
    await environment.clipboard.writeText(text);
    return "clipboard";
  }
  if (environment.document === undefined) {
    throw new Error("Clipboard access is unavailable in this environment.");
  }
  const textarea = environment.document.createElement("textarea");
  textarea.value = text;
  textarea.setAttribute("readonly", "");
  textarea.style.position = "fixed";
  textarea.style.opacity = "0";
  environment.document.body.append(textarea);
  try {
    textarea.select();
    const copied = environment.document.execCommand("copy");
    if (!copied) throw new Error("The browser rejected the clipboard fallback.");
    return "fallback";
  } finally {
    textarea.remove();
  }
}

export interface CopyButtonProps extends Omit<
  ButtonHTMLAttributes<HTMLButtonElement>,
  "children" | "onCopy" | "onError"
> {
  readonly text: string;
  readonly copyLabel?: string;
  readonly copyingLabel?: string;
  readonly copiedLabel?: string;
  readonly errorLabel?: string;
  readonly onCopy?: (method: "clipboard" | "fallback") => void;
  readonly onCopyError?: (error: unknown) => void;
}

export const CopyButton = forwardRef<HTMLButtonElement, CopyButtonProps>(function CopyButton(
  {
    className,
    copiedLabel: copiedLabelProp,
    copyingLabel: copyingLabelProp,
    copyLabel: copyLabelProp,
    disabled = false,
    errorLabel: errorLabelProp,
    onClick,
    onCopy,
    onCopyError,
    text,
    type = "button",
    ...nativeProps
  },
  ref,
) {
  const [status, setStatus] = useState<CopyButtonStatus>("idle");
  const defaultCopiedLabel = useMergoraMessage("copyButton.copied", "Copied");
  const defaultCopyingLabel = useMergoraMessage("copyButton.copying", "Copying");
  const defaultCopyLabel = useMergoraMessage("copyButton.copy", "Copy");
  const defaultErrorLabel = useMergoraMessage("copyButton.error", "Copy failed");
  const copiedLabel = copiedLabelProp ?? defaultCopiedLabel;
  const copyingLabel = copyingLabelProp ?? defaultCopyingLabel;
  const copyLabel = copyLabelProp ?? defaultCopyLabel;
  const errorLabel = errorLabelProp ?? defaultErrorLabel;
  const pending = status === "copying";
  const label =
    status === "copying"
      ? copyingLabel
      : status === "copied"
        ? copiedLabel
        : status === "error"
          ? errorLabel
          : copyLabel;

  const handleClick: MouseEventHandler<HTMLButtonElement> = (event) => {
    const activation = runButtonActivation(pending, event, onClick);
    if (activation === "prevented-pending" || event.defaultPrevented) return;
    setStatus("copying");
    void writeClipboardText(text).then(
      (method) => {
        setStatus("copied");
        onCopy?.(method);
      },
      (error: unknown) => {
        setStatus("error");
        onCopyError?.(error);
      },
    );
  };

  return (
    <button
      {...nativeProps}
      aria-busy={pending || undefined}
      aria-disabled={pending || nativeProps["aria-disabled"]}
      className={className === undefined ? "mrg-copy-button" : `mrg-copy-button ${className}`}
      data-slot="copy-button"
      data-status={status}
      disabled={disabled}
      onClick={handleClick}
      ref={ref}
      type={type}
    >
      <span aria-hidden="true" data-slot="copy-button-icon">
        {status === "copied" ? "✓" : status === "error" ? "!" : "⧉"}
      </span>
      <span aria-live="polite" data-slot="copy-button-status">
        {label}
      </span>
    </button>
  );
});

CopyButton.displayName = "CopyButton";
Object.defineProperty(CopyButton, Symbol.for("mergora-ui/toolbar-action"), { value: true });
